import{getOverflowAncestors}from"../../lib/floating";const swipeBackExcludedSelector="input, textarea, [data-vkui-swipe-back=false]";function swipeBackExcluded(e){const t=e.originalEvent.target;return Boolean(t?.closest?.(swipeBackExcludedSelector))}function hasHorizontalScrollableElementWithScrolledToLeft(e){return getOverflowAncestors(e).some(e=>"scrollLeft"in e&&0<e.scrollLeft)}const SWIPE_BACK_EDGE_SIZE_THRESHOLD=20,SWIPE_BACK_SHIFT_THRESHOLD=10,getSwipeBackPredicates=(e,t,o)=>{return{swipedToOpposite:t<0,swipeBackTriggered:t>=SWIPE_BACK_SHIFT_THRESHOLD,viewportStartEdgeTouched:e<=SWIPE_BACK_EDGE_SIZE_THRESHOLD,viewportEndEdgeTouched:e>=o-SWIPE_BACK_EDGE_SIZE_THRESHOLD}};export{swipeBackExcluded,hasHorizontalScrollableElementWithScrolledToLeft,SWIPE_BACK_EDGE_SIZE_THRESHOLD,SWIPE_BACK_SHIFT_THRESHOLD,getSwipeBackPredicates};